import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"回城卷轴","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/9.消耗品/0.无支线/回城卷轴.md","filePath":"4.资源分区/7.物品与装备/9.消耗品/0.无支线/回城卷轴.md"}'),o={name:"4.资源分区/7.物品与装备/9.消耗品/0.无支线/回城卷轴.md"};function d(l,a,_,i,b,c){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"回城卷轴",tabindex:"-1"},[n("回城卷轴 "),e("a",{class:"header-anchor",href:"#回城卷轴","aria-label":'Permalink to "回城卷轴"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),s('<h1 id="回城卷轴-1" tabindex="-1">回城卷轴 <a class="header-anchor" href="#回城卷轴-1" aria-label="Permalink to &quot;回城卷轴&quot;">​</a></h1><p>回城卷轴（消耗品）<br> 250<br> 英雄真正需要的东西。</p><p>一捆记载了回城魔法的卷轴，使用一次就会被消耗殆尽。<br> 需提前花费10分钟在某地设置一个坐标，<br> 随后激活回城卷轴的时候，在10分钟到1小时不等的时间后（根据距离而定），<br> 该传送具有一个最大距离，最大距离约为一小时的引导后从城市一段到另一端，或者一小时的引导后传送到相邻城市，<br> 你会完成施法，这会在你面前展开一个传送回坐标的传送门，这是一个D级的旅行效果。</p><p>远行靴<br> 占据鞋袜位<br> D+500</p><p>“足生双翼，上天入地”</p><p>这是一双有着神奇魔力的靴子，在兑换这双靴子之后，你的基础移动速度上升敏捷属性*1M。<br> 你可以下意识知道你的所有轮回者队友的位置（除非对方主动屏蔽了你），<br> 选择你使用回城卷轴时可以选择轮回者队友的身边为传送的落点坐标，并且回城卷轴现在不再消耗，但仍承受回城卷轴的距离限制。</p><p>你也可以选择让轮回者队友的位置在轮回者手表上以小地图的形式显示，若如此做，那么你们还能通过轮回者手表进行交流。</p><p>——额外支付D+500将该奇物差升至C级。</p><p>在使用回城卷轴时，你能选定的传送范围从轮回者队友身边扩大至只需要知道具体坐标，<br> 原先的传送最大距离扩大，当前你可以从大陆内的一端传送至另一端，这是一个C级的旅行效果，<br> 你的基础移动速度上升敏捷属性*2+8M。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
